          {isLoaded && (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={isActive ? { opacity: 0.4 } : { opacity: 0 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.5 }}
              className="absolute inset-0 z-0 bg-cover bg-center brightness-[0.4]"
              style={{ 
                y: backgroundY, 
                backgroundImage: `url(${backgroundImage})` 
              }}
