              className="group bg-primary text-white font-bold py-5 px-10 md:py-6 md:px-16 rounded-xl flex items-center justify-center gap-5 transition-all shadow-2xl shadow-primary/30 w-fit cursor-pointer border border-primary/20"
            >
              <span className="text-[10px] md:text-[11px] uppercase tracking-[0.4em] font-black">{data.button}</span>
              <ArrowRight size={22} className="group-hover:translate-x-2 transition-transform text-white/80" />
            </motion.a>
          </div>
        </motion.div>
      </div>

      {/* Redesigned Minimalist Horizontal Footer */}
      <footer className="absolute bottom-6 md:bottom-10 left-6 md:left-20 lg:left-32 right-6 md:right-20 lg:right-32 z-20">
