              <MapPin size={10} className="text-primary/60 group-hover:text-primary transition-colors" />
              <span className="text-[8px] uppercase tracking-[0.25em] font-bold text-white/30 group-hover:text-white/50 transition-colors">{data.info.address}</span>
            </div>

            <div className="hidden sm:block w-[1px] h-2 bg-white/10" />

            <a href={`tel:${data.info.phone.replace(/\s/g, '')}`} className="flex items-center gap-2 group">
              <Phone size={10} className="text-primary/60 group-hover:text-primary transition-colors" />
              <span className="text-[8px] uppercase tracking-[0.25em] font-bold text-white/30 group-hover:text-white/50 transition-colors">{data.info.phone}</span>
            </a>

            <div className="hidden sm:block w-[1px] h-2 bg-white/10" />

            <a href={`mailto:${data.info.email}`} className="flex items-center gap-2 group">
              <Mail size={10} className="text-primary/60 group-hover:text-primary transition-colors" />
              <span className="text-[8px] uppercase tracking-[0.25em] font-bold text-white/30 group-hover:text-white/50 transition-colors">{data.info.email}</span>
            </a>
          </div>

          {/* Copyright Group */}
